#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,m,t;
	cin>>t;
	while(t--){
	    cin>>n>>m;
	    if(n==0 && m%2==0)cout<<"Yes";
	    else if(n==0 && m%2==1)cout<<"No";
	    //当n等于0且m为偶数，则存在a数列
        else if(n && m%2==1)cout<<"Yes";
        else cout<<"No";
        //否则当n大于0且m为奇数，则存在a数列
        cout<<endl;
	} 
    return 0;
}
